INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (198, 136477, 1, 416, '爱是个坏东西', '天空下着绵绵细雨，我的心中不禁想起箫亚轩《爱是个坏东西》。我哼着那段：“爱是个坏东西，让我变得爱笑爱哭泣，早知道太好奇，总难免会伤到自己。夜里不适合想你，可不想睡不着，把自己搞得神经兮兮，然后再来怪你，我试着提醒自己，和你不过朋友而已，就是那样的距离，叫人受不了，等不及，爱是个坏东西.......”
<br>    确实，我和他只不过朋友而已。我努力地尝试着只把他当做朋友，可是我对他的感情已经超过了朋友的那种感情了。我曾经想想他表白，可我始终开不了口。我知道他只把我当作朋友，他还深深喜欢着一个女生。最终，我选折了放弃。我想，还是和他作朋友比较好......
<br>    天空的雨依然下着，那种气息，教人逃不开，挥不去......', '天空下着绵绵细雨，我的心中不禁想起箫亚轩《爱是个坏东西》。我哼着那段：“爱是个坏东西，让我变得爱笑爱哭泣，早知道太好奇，总难免会伤到自己。夜里不适合想你，可不想睡不着，把自己搞得神经兮兮，然后再来怪你，我试着提醒自己，和你不过朋友而已，就是那样的距离，叫人受不了，等不及，爱是个坏东西.......”

确实，我和他只不过朋友而已。我努力地尝试着只把他当做朋友，可是我对他的感情已经超过了朋友的那种感情了。我曾经想想他表白，可我始终开不了口。我知道他只把我当作朋友，他还深深喜欢着一个女生。最终，我选折了放弃。我想，还是和他作朋友比较好......

天空的雨依然下着，那种气息，教人逃不开，挥不去......', 'L.Y幻想灵', '2001-12-09 14:08:00', 3, '20020112094907_bbsid_136477_board_1_86fa8dc334.html', '20020112094907');
